import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

// --- HELPER FUNCTIONS (BỘ LỌC) ---
const isSameDay = (d1, d2) => d1.toDateString() === d2.toDateString();
const isSameMonth = (d1, d2) => d1.getMonth() === d2.getMonth() && d1.getFullYear() === d2.getFullYear();
const isSameWeek = (d1, d2) => {
    const start = new Date(d2);
    start.setHours(0,0,0,0);
    start.setDate(start.getDate() - start.getDay() + 1); 
    const end = new Date(start);
    end.setDate(end.getDate() + 6);
    return d1 >= start && d1 <= end;
};

// --- ICONS (TỐI GIẢN - XANH DƯƠNG ĐẬM) ---
const Icons = {
  Finance: () => (
    <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5">
      <path strokeLinecap="round" strokeLinejoin="round" d="M12 6v12m-3-2.818l.879.659c1.171.879 3.07.879 4.242 0 1.172-.879 1.172-2.303 0-3.182C13.536 12.219 12.768 12 12 12c-.725 0-1.45-.22-2.003-.659-1.106-.879-1.106-2.303 0-3.182s2.9-.879 4.006 0l.415.33M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
  ),
  Facility: () => (
    <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5">
      <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 12l8.954-8.955c.44-.439 1.152-.439 1.591 0L21.75 12M4.5 9.75v10.125c0 .621.504 1.125 1.125 1.125H9.75v-4.875c0-.621.504-1.125 1.125-1.125h2.25c.621 0 1.125.504 1.125 1.125V21h4.125c.621 0 1.125-.504 1.125-1.125V9.75M8.25 21h8.25" />
    </svg>
  ),
  Task: () => (
    <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5">
      <path strokeLinecap="round" strokeLinejoin="round" d="M9 12h3.75M9 15h3.75M9 18h3.75m3 .75H18a2.25 2.25 0 002.25-2.25V6.108c0-1.135-.845-2.098-1.976-2.192a48.424 48.424 0 00-1.123-.08m-5.801 0c-.065.21-.1.433-.1.664 0 .414.336.75.75.75h4.5a.75.75 0 00.75-.75 2.25 2.25 0 00-.1-.664m-5.8 0A2.251 2.251 0 0113.5 2.25H15c1.012 0 1.867.668 2.15 1.586m-5.8 0c-.376.023-.75.05-1.124.08C9.095 4.01 8.25 4.973 8.25 6.108V8.25m0 0H4.875c-.621 0-1.125.504-1.125 1.125v11.25c0 .621.504 1.125 1.125 1.125h9.75c.621 0 1.125-.504 1.125-1.125V9.375c0-.621-.504-1.125-1.125-1.125H8.25zM6.75 12h.008v.008H6.75V12zm0 3h.008v.008H6.75V15zm0 3h.008v.008H6.75V18z" />
    </svg>
  ),
  Schedule: () => (
    <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5">
      <path strokeLinecap="round" strokeLinejoin="round" d="M6.75 3v2.25M17.25 3v2.25M3 18.75V7.5a2.25 2.25 0 012.25-2.25h13.5A2.25 2.25 0 0121 7.5v11.25m-18 0A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75m-18 0v-7.5A2.25 2.25 0 015.25 9h13.5A2.25 2.25 0 0121 11.25v7.5" />
    </svg>
  ),
  Print: () => (
    <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
      <path strokeLinecap="round" strokeLinejoin="round" d="M6.72 13.829c-.24.03-.48.062-.72.096m.72-.096a42.415 42.415 0 0110.56 0m-10.56 0L6.34 18m10.94-4.171c.24.03.48.062.72.096m-.72-.096L17.66 18m0 0l.229 2.523a1.125 1.125 0 01-1.12 1.227H7.231c-.662 0-1.18-.568-1.12-1.227L6.34 18m11.318 0h1.091A2.25 2.25 0 0021 15.75V9.456c0-1.081-.768-2.015-1.837-2.175a48.055 48.055 0 00-1.913-.247M6.34 18H5.25A2.25 2.25 0 013 15.75V9.456c0-1.081.768-2.015 1.837-2.175a48.041 48.041 0 011.913-.247m10.5 0a48.536 48.536 0 00-10.5 0m10.5 0V3.375c0-.621-.504-1.125-1.125-1.125h-8.25c-.621 0-1.125.504-1.125 1.125v3.659M18 10.5h.008v.008H18V10.5zm-3 0h.008v.008H15V10.5z" />
    </svg>
  )
};

const Reports = () => {
  const { tasks, staffList, facilityLogs } = useData();
  const [attendanceFilter, setAttendanceFilter] = useState('month');

  // --- HÀM XỬ LÝ IN ---
  const handlePrint = () => {
    window.print();
  };

  // --- PHÂN TÁCH DỮ LIỆU ---
  const opAdminTasks = tasks.filter(t => !t.fromScheduleId);
  const scheduleTasks = tasks.filter(t => t.fromScheduleId);

  // --- LOGIC TÍNH TOÁN OP ADMIN ---
  const totalTasks = opAdminTasks.length;
  const completedTasks = opAdminTasks.filter(t => t.status === 'completed').length;
  const taskProgress = totalTasks === 0 ? 0 : Math.round((completedTasks / totalTasks) * 100);

  // --- LOGIC LỌC CHẤM CÔNG ---
  const filteredAttendance = scheduleTasks.filter(t => {
      const taskDate = new Date(t.startTime);
      const now = new Date();
      if (attendanceFilter === 'day') return isSameDay(taskDate, now);
      if (attendanceFilter === 'week') return isSameWeek(taskDate, now);
      if (attendanceFilter === 'month') return isSameMonth(taskDate, now);
      return true;
  });

  return (
    <div style={{ paddingBottom: '40px' }} className="reports-page">
      {/* CSS CHO IN ẤN & BẢNG BIỂU RÕ CỘT */}
      <style>{`
        /* Style cho bảng hiển thị rõ cột (Grid) */
        .report-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.9rem;
        }
        .report-table th, .report-table td {
          border: 1px solid #d1d5db; /* Viền xám rõ ràng cho từng ô */
          padding: 10px 12px;
          text-align: left;
        }
        .report-table th {
          background-color: #f3f4f6; /* Nền header xám nhẹ */
          color: #374151;
          font-weight: 700;
          text-transform: uppercase;
          font-size: 0.8rem;
        }
        .report-table tr:nth-child(even) {
          background-color: #f9fafb; /* Xen kẽ màu dòng */
        }

        /* Ẩn các thành phần không cần thiết khi in */
        @media print {
          .admin-sidebar, .admin-header-mobile, .admin-bottom-nav, .btn-print, .filter-select {
            display: none !important;
          }
          .admin-content {
            margin: 0 !important;
            padding: 0 !important;
            width: 100% !important;
          }
          body {
            background: white;
            -webkit-print-color-adjust: exact;
          }
          .card {
            box-shadow: none !important;
            border: 1px solid #000 !important;
            break-inside: avoid;
            margin-bottom: 20px !important;
          }
          .report-table th, .report-table td {
            border: 1px solid #000 !important; /* Viền đen đậm khi in */
          }
        }
      `}</style>

      {/* HEADER + NÚT IN */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid #e5e7eb', paddingBottom: '15px', marginBottom: '20px' }}>
         <h2 style={{ color: '#003366', margin: 0, fontWeight: '700' }}>Báo cáo Quản trị</h2>
         <button onClick={handlePrint} className="btn-print" style={styles.printBtn}>
            <Icons.Print /> Xuất Báo cáo
         </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px', marginBottom: '30px' }}>
        
        {/* --- CARD 1: TÀI CHÍNH (GIỮ NGUYÊN) --- */}
        <div style={styles.card} className="card">
           <div style={styles.cardHeader}>
              <div style={styles.iconBox}><Icons.Finance /></div>
              <h3 style={styles.cardTitle}>Tài chính & Thu nhập (Chief Admin)</h3>
           </div>
           <div style={styles.cardBody}>
              <div style={styles.statRow}>
                 <span>Tổng chi dự kiến:</span>
                 <strong>--- VNĐ</strong>
              </div>
              <div style={{fontSize:'0.8rem', color:'#6b7280', marginTop:'10px'}}>
                *Chức năng đang phát triển
              </div>
           </div>
        </div>

        {/* --- CARD 2: CƠ SỞ VẬT CHẤT (GIỮ NGUYÊN) --- */}
        <div style={styles.card} className="card">
           <div style={styles.cardHeader}>
              <div style={styles.iconBox}><Icons.Facility /></div>
              <h3 style={styles.cardTitle}>Tình trạng Cơ sở vật chất</h3>
           </div>
           <div style={styles.cardBody}>
               <div style={styles.statRow}>
                 <span>Số lần kiểm tra:</span>
                 <strong>{facilityLogs.length}</strong>
               </div>
               <div style={styles.statRow}>
                 <span>Báo cáo gần nhất:</span>
                 <strong>{facilityLogs.length > 0 ? new Date(facilityLogs[facilityLogs.length-1].timestamp).toLocaleDateString() : 'N/A'}</strong>
               </div>
           </div>
        </div>
      </div>

      {/* --- SECTION: BÁO CÁO CHẤM CÔNG (SCHEDULER) --- */}
      <div style={styles.card} className="card">
          <div style={{ ...styles.cardHeader, justifyContent: 'space-between' }}>
             <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={styles.iconBox}><Icons.Schedule /></div>
                <h3 style={styles.cardTitle}>Báo cáo Chấm công (Theo Lịch Scheduler)</h3>
             </div>
             
             <select 
                  value={attendanceFilter} 
                  onChange={(e) => setAttendanceFilter(e.target.value)}
                  style={styles.filterSelect}
                  className="filter-select"
              >
                  <option value="day">Hôm nay</option>
                  <option value="week">Tuần này</option>
                  <option value="month">Tháng này</option>
              </select>
          </div>
          <div style={styles.cardBody}>
             <table className="report-table">
                <thead>
                   <tr>
                     <th>Nhân sự</th>
                     <th>Ca làm việc</th>
                     <th>Thời gian</th>
                     <th>Trạng thái</th>
                     <th>Kết quả</th>
                   </tr>
                </thead>
                <tbody>
                   {filteredAttendance.length > 0 ? filteredAttendance.map(t => (
                     <tr key={t.id}>
                        <td style={{ fontWeight: '600' }}>{t.assigneeName}</td>
                        <td>
                            <div>{t.title}</div>
                            <div style={{fontSize:'0.75rem', color:'#6b7280'}}>{t.assignedRole}</div>
                        </td>
                        <td>
                           {new Date(t.startTime).toLocaleDateString('vi-VN')} <br/>
                           <span style={{fontSize:'0.8rem', color:'#6b7280'}}>
                             {new Date(t.startTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})} - {new Date(t.endTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                           </span>
                        </td>
                        <td>
                           {t.status === 'completed' || t.progress === 100 ? 
                             <span style={{color:'green', background:'#dcfce7', padding:'2px 8px', borderRadius:'4px', fontSize:'0.75rem', fontWeight:'bold'}}>Đã chấm công</span> : 
                             <span style={{color:'#d97706', background:'#fef3c7', padding:'2px 8px', borderRadius:'4px', fontSize:'0.75rem', fontWeight:'bold'}}>Chưa hoàn thành</span>
                           }
                        </td>
                        <td>{t.progress}%</td>
                     </tr>
                   )) : (
                     <tr><td colSpan="5" style={{textAlign:'center', color:'#9ca3af', fontStyle:'italic'}}>Không có dữ liệu chấm công.</td></tr>
                   )}
                </tbody>
             </table>
          </div>
      </div>

      {/* --- SECTION: TIẾN ĐỘ CÔNG VIỆC (OP ADMIN) --- */}
      <div style={{ marginTop: '30px' }}>
        <div style={styles.card} className="card">
          <div style={styles.cardHeader}>
             <div style={styles.iconBox}><Icons.Task /></div>
             <h3 style={styles.cardTitle}>Tiến độ Công việc (Operational Admin giao)</h3>
          </div>
          <div style={styles.cardBody}>
            <div style={{ marginBottom: '20px', display: 'flex', gap: '20px' }}>
                <div style={{flex:1, background:'#f9fafb', padding:'15px', borderRadius:'8px', border: '1px solid #e5e7eb'}}>
                    <div style={{fontSize:'0.8rem', color:'#6b7280'}}>Tổng nhiệm vụ</div>
                    <div style={{fontSize:'1.5rem', fontWeight:'bold', color:'#003366'}}>{totalTasks}</div>
                </div>
                <div style={{flex:1, background:'#f9fafb', padding:'15px', borderRadius:'8px', border: '1px solid #e5e7eb'}}>
                    <div style={{fontSize:'0.8rem', color:'#6b7280'}}>Hoàn thành</div>
                    <div style={{fontSize:'1.5rem', fontWeight:'bold', color:'#059669'}}>{completedTasks}</div>
                </div>
                <div style={{flex:1, background:'#f9fafb', padding:'15px', borderRadius:'8px', border: '1px solid #e5e7eb'}}>
                    <div style={{fontSize:'0.8rem', color:'#6b7280'}}>Tỷ lệ</div>
                    <div style={{fontSize:'1.5rem', fontWeight:'bold', color:'#003366'}}>{taskProgress}%</div>
                </div>
            </div>

            <table className="report-table">
              <thead>
                <tr>
                  <th>Nhiệm vụ</th>
                  <th>Phụ trách</th>
                  <th>Hạn chót</th>
                  <th>Tiến độ</th>
                  <th>Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                  {opAdminTasks.map(task => {
                    let statusColor = '#3b82f6';
                    let statusText = 'Đang làm';
                    if (task.status === 'completed') { statusColor = '#10b981'; statusText = 'Xong'; }
                    
                    const statusElement = (
                       <span style={{ fontSize: '0.75rem', fontWeight: '600', color: statusColor, background: `${statusColor}20`, padding: '4px 8px', borderRadius: '4px' }}>
                          {statusText}
                       </span>
                    );

                    return (
                      <tr key={task.id}>
                        <td style={{ fontWeight: '500' }}>{task.title}</td>
                        <td>{task.assigneeName}</td>
                        <td>{new Date(task.endTime).toLocaleDateString('vi-VN')}</td>
                        <td>
                           <div style={{display:'flex', alignItems:'center', gap:'8px'}}>
                              <div style={{flex:1, height:'6px', background:'#e5e7eb', borderRadius:'3px', minWidth:'60px'}}>
                                <div style={{width:`${task.progress}%`, background:'#003366', height:'100%', borderRadius:'3px'}}></div>
                              </div>
                              <span style={{fontSize:'0.8em', fontWeight:'bold'}}>{task.progress}%</span>
                           </div>
                        </td>
                        <td>{statusElement}</td>
                      </tr>
                    );
                  })}
                  {opAdminTasks.length === 0 && <tr><td colSpan="5" style={{textAlign:'center', color:'#9ca3af', fontStyle:'italic'}}>Chưa có nhiệm vụ Op Admin.</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

const styles = {
  card: {
    background: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)',
    border: '1px solid #e5e7eb',
    marginBottom: '30px',
    overflow: 'hidden'
  },
  cardHeader: {
    padding: '16px 20px',
    borderBottom: '1px solid #e5e7eb',
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    background: '#f9fafb'
  },
  iconBox: {
    width: '36px', height: '36px',
    background: '#e0f2fe', borderRadius: '8px',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    color: '#003366'
  },
  cardTitle: {
    margin: 0,
    fontSize: '1rem',
    fontWeight: '600',
    color: '#1f2937'
  },
  cardBody: {
    padding: '20px'
  },
  statRow: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '8px',
    fontSize: '0.9rem',
    color: '#4b5563'
  },
  filterSelect: {
    padding: '8px 12px', 
    borderRadius: '8px', 
    border: '1px solid #e5e7eb', 
    outline: 'none', 
    fontWeight: '600', 
    color: '#4b5563', 
    cursor: 'pointer'
  },
  printBtn: {
    display: 'flex', alignItems: 'center', gap: '8px',
    background: 'white', color: '#003366',
    border: '1px solid #003366', borderRadius: '8px',
    padding: '8px 16px', fontWeight: '600', cursor: 'pointer',
    transition: 'all 0.2s'
  }
};

export default Reports;
